#@help _wireguard_connect1
# @internal connect chain step (emits the connect commands)
#@end
_wireguard_connect1() {
  local session_id="$1"
  local session_dir="$VPN_SWITCH_BASE/.session/$session_id"
  local interface="${VPN_SWITCH_INTERFACE_wireguard}"
  local patched_config="$session_dir/${interface}.conf"
  local connect_script="$session_dir/connect.sh"
  local disconnect_script="$session_dir/disconnect.sh"
  local session_proto_dir="$VPN_SWITCH_BASE/session"

  # Validate session exists
  if [ ! -d "$session_dir" ]; then
    generate_error "Session not found: $session_id"
    return 0
  fi

  # Validate patched config exists
  if [ ! -f "$patched_config" ]; then
    generate_error "Patched config not found in session $session_id: $patched_config"
    return 0
  fi

  # Read original config path from session metadata
  local original_config=$(cat "$session_dir/original" 2>>"$LOG_FILE" || echo "unknown")

  # Compute relative path from session directory to original config
  # Session is at: $VPN_SWITCH_BASE/.session/$session_id/
  # Original is at: $VPN_SWITCH_BASE/wireguard/... or $VPN_SWITCH_BASE/wireguard/category/...
  # Relative path: ../../wireguard/... or ../../wireguard/category/...
  local original_config_relative="${original_config#$VPN_SWITCH_BASE/}"
  original_config_relative="../../$original_config_relative"

  # NOTE: Duplicate session check moved to __wireguard_start1 (before session creation)
  # This prevents PID mismatch issues in the combinator chain

  # Extract DNS server for firewall table (from patched config)
  local dns_server=$(grep '^DNS' "$patched_config" | head -1 | awk -F= '{print $2}')
  dns_server="${dns_server:-${VPN_SWITCH_DNS_wireguard:-10.2.0.1}}"  # VPN provider WireGuard uses 10.2.0.1

  # Extract remote server IPs for firewall table (from patched config)
  local remote_ips=$(get_wireguard_remotes "$patched_config")

  # Get phase lists
  local phases_connect="${VPN_SWITCH_PHASES_CONNECT:-firewall vpn dns}"
  local phases_disconnect="${VPN_SWITCH_PHASES_DISCONNECT:-dns vpn firewall}"

  # Phase script directory
  local phase_dir="$VPN_SWITCH_BASE/.include/phase/wireguard"

  # Strict phase resolution (least surprise): every phase in the list MUST
  # resolve to a script. A phase that does not resolve is a configuration error
  # and aborts generation — it is never silently dropped (which previously could
  # remove e.g. the firewall phase on a typo or a missing @profile). To skip a
  # phase on purpose, use the ':none' backend. Supports :variant@profile syntax.
  local protocol=$(basename -- "$phase_dir")  # Extract protocol from phase_dir
  for phase_spec in $phases_connect; do
    if ! resolve_phase_script "$phase_spec" "$protocol" "connect" "$VPN_SWITCH_BASE" >/dev/null 2>&1; then
      generate_error "Phase '$phase_spec' (connect) does not resolve" "Fix VPN_SWITCH_PHASES_CONNECT or add the backend; use ':none' to skip a phase"
      return 0
    fi
  done
  for phase_spec in $phases_disconnect; do
    if ! resolve_phase_script "$phase_spec" "$protocol" "disconnect" "$VPN_SWITCH_BASE" >/dev/null 2>&1; then
      generate_error "Phase '$phase_spec' (disconnect) does not resolve" "Fix VPN_SWITCH_PHASES_DISCONNECT or add the backend; use ':none' to skip a phase"
      return 0
    fi
  done

  # Build VPN_SWITCH_CONTEXT_CONNECT (new context variable system)
  # Gateway for WireGuard is the DNS server
  local gateway="$dns_server"
  VPN_SWITCH_CONTEXT_CONNECT="
export VPN_SESSION_DIR=\"$session_dir\"
export VPN_SESSION_PID=\"$session_id\"
export VPN_CONFIG_FILE=\"$patched_config\"
export VPN_ORIGINAL_CONFIG=\"$original_config\"
export VPN_ORIGINAL_CONFIG_RELATIVE=\"$original_config_relative\"
export VPN_INTERFACE=\"$VPN_SWITCH_INTERFACE_wireguard\"
export VPN_DNS_SERVER=\"$dns_server\"
export VPN_REMOTE_IPS=\"$remote_ips\"
export VPN_GATEWAY=\"$gateway\"
export VPN_PROTOCOL=\"wireguard\"
export VPN_PHASES_CONNECT=\"$phases_connect\"
export VPN_PHASES_DISCONNECT=\"$phases_disconnect\"
"
  export VPN_SWITCH_CONTEXT_CONNECT

  # Generate connect.sh using phase-based approach
  {
    # Generate prologue
    if [ -f "$phase_dir/connect/prologue.sh" ]; then
      run_env -- sh "$phase_dir/connect/prologue.sh"
    else
      generate_error "Prologue not found: $phase_dir/connect/prologue.sh"
      return 0
    fi

    # Generate phases (verify → prepare → execute for each phase)
    for phase_spec in $phases_connect; do
      local phase_script=$(resolve_phase_script "$phase_spec" "$protocol" "connect" "$VPN_SWITCH_BASE")
      if [ -n "$phase_script" ] && [ -f "$phase_script" ]; then
        run_env -- sh "$phase_script" verify
        run_env -- sh "$phase_script" prepare
        run_env -- sh "$phase_script" execute
      fi
      # Pre-flight above guarantees every phase resolves (missing => error, not skip)
    done
  } > "$connect_script"

  $MODIFY_FILE_PERMS 0750 "$connect_script"

  # Claim interface ownership only when this session's config is actually the one
  # loaded on the interface. A self-validating claim keeps session/latest-$interface
  # from drifting: previously this symlink was set unconditionally at the end of
  # connect.sh, so a resume whose `wg-quick up` failed (e.g. the interface was
  # already up with a different config) would still claim ownership of someone
  # else's tunnel. We compare the live peer set against this session's config and
  # only claim on a match. Cf. session_peer_matches_interface() in vpn-switch.sh
  # (same fingerprint, used by is_session_alive) and 'vpn-switch session refresh'
  # (reconciles drift after the fact).
  {
    echo ""
    echo "# Claim interface ownership (only if our config is the one loaded)"
    cat <<EOF
__vpn_loaded=\$($EXAMINE_VPN_WIREGUARD_INTERFACE "\$interface" 2>/dev/null | grep '^peer:' | sed 's/^peer:[[:space:]]*//' | sort)
__vpn_ours=\$(grep -i '^[[:space:]]*PublicKey' "\$config_path" 2>/dev/null | sed 's/^[[:space:]]*[Pp]ublic[Kk]ey[[:space:]]*=[[:space:]]*//' | sort)
if [ -n "\$__vpn_loaded" ] && [ "\$__vpn_loaded" = "\$__vpn_ours" ]; then
  $MODIFY_LINK_FORCE "../.session/$session_id" "$session_proto_dir/latest-$interface"
  echo "# Interface ownership claimed: $interface -> session $session_id" >&2
else
  echo "WARNING: $interface not loaded with this session's config - ownership not claimed" >&2
  echo "WARNING: if the VPN is up, run 'vpn-switch session refresh' to reconcile" >&2
fi
EOF
  } >> "$connect_script"

  # Generate disconnect.sh using phase-based approach
  {
    # Generate prologue
    if [ -f "$phase_dir/disconnect/prologue.sh" ]; then
      run_env -- sh "$phase_dir/disconnect/prologue.sh"
    else
      generate_error "Prologue not found: $phase_dir/disconnect/prologue.sh"
      return 0
    fi

    # Generate phases (verify → prepare → execute for each phase)
    for phase_spec in $phases_disconnect; do
      local phase_script=$(resolve_phase_script "$phase_spec" "$protocol" "disconnect" "$VPN_SWITCH_BASE")
      if [ -n "$phase_script" ] && [ -f "$phase_script" ]; then
        run_env -- sh "$phase_script" verify
        run_env -- sh "$phase_script" prepare
        run_env -- sh "$phase_script" execute
      fi
      # Pre-flight above guarantees every phase resolves (missing => error, not skip)
    done
  } > "$disconnect_script"

  # Release interface ownership: drop latest-$interface if it still points to
  # this session, so a stopped session never keeps claiming the interface (this
  # is the other half of preventing ownership drift; previously disconnect left
  # the symlink behind).
  {
    echo ""
    echo "# Release interface ownership (only if still ours)"
    cat <<EOF
if [ -L "$session_proto_dir/latest-$interface" ] && [ "\$($EXAMINE_LINK_TARGET "$session_proto_dir/latest-$interface" 2>/dev/null)" = "../.session/$session_id" ]; then
  $MODIFY_LINK_REMOVE "$session_proto_dir/latest-$interface"
  echo "# Interface ownership released: $interface (was session $session_id)" >&2
fi
EOF
  } >> "$disconnect_script"

  $MODIFY_FILE_PERMS 0750 "$disconnect_script"

  # Output connect script for immediate execution
  cat "$connect_script"
}

#@help _wireguard_disconnect1
# @internal disconnect chain step (emits the disconnect commands)
#@end
_wireguard_disconnect1() {
  local interface="$1"

  # Find session by interface name
  local session_pid=$(find_session_by_interface "$interface")

  if [ -z "$session_pid" ]; then
    generate_error "No vpn-switch session found for interface: $interface"
    return 0
  fi

  local session_dir="$VPN_SWITCH_BASE/.session/$session_pid"
  local disconnect_script="$session_dir/disconnect.sh"

  # Build VPN_SWITCH_CONTEXT_DISCONNECT (new context variable system)
  VPN_SWITCH_CONTEXT_DISCONNECT="
export VPN_SESSION_DIR='$session_dir'
export VPN_SESSION_PID='$session_pid'
export VPN_INTERFACE='$interface'
export VPN_PROTOCOL='wireguard'
"
  export VPN_SWITCH_CONTEXT_DISCONNECT

  # If disconnect.sh exists (phase-based sessions), use it
  if [ -f "$disconnect_script" ]; then
    cat "$disconnect_script"
  else
    # Legacy fallback for old sessions created before phase-based implementation
    local original_config=$(cat "$session_dir/original" 2>>"$LOG_FILE" || echo "unknown")
    local original_config_relative="${original_config#$VPN_SWITCH_BASE/}"
    original_config_relative="../../$original_config_relative"

    local wg_quick="$VPN_SWITCH_BINARY_wireguard"
    local pfctl="${VPN_SWITCH_PFCTL:-pfctl}"
    local vpn_dns_table="${VPN_SWITCH_VPN_DNS_TABLE:-vpn_dns}"
    local vpn_remotes_table="${VPN_SWITCH_VPN_REMOTES_TABLE:-vpn_remotes}"

    # Generate legacy cleanup commands
    cat <<EOF
# Disconnect WireGuard interface: $interface (legacy mode - no disconnect.sh found)
# Session PID: $session_pid
# Original config: $original_config_relative

# Kill wg-quick process group (including background route monitors)
if [ -f "$session_dir/wg_quick_pid" ]; then
  wg_quick_pid=\$(cat "$session_dir/wg_quick_pid" 2>>"$LOG_FILE")
  if [ -n "\$wg_quick_pid" ]; then
    echo "Killing wg-quick process group (PID: \$wg_quick_pid)..."
    kill -TERM -- -\$wg_quick_pid 2>>"$LOG_FILE" || true
    sleep 1
  fi
fi

# Stop WireGuard interface
echo "Stopping WireGuard interface: $interface"
$wg_quick down "$interface" 2>>"$LOG_FILE" || true

# Clean up firewall tables
echo "Cleaning up firewall tables..."
$pfctl -t "$vpn_dns_table" -T flush 2>>"$LOG_FILE" || true
$pfctl -t "$vpn_remotes_table" -T flush 2>>"$LOG_FILE" || true

echo "VPN disconnected: $interface"
echo "Note: Session metadata will be cleaned up by 'session stop'"
EOF
  fi
}

