#@help _wireguard_enumerate0
# @internal WireGuard enumeration helper
#@end
_wireguard_enumerate0() {
  # Process Table Analysis - enumerate running WireGuard processes
  # Generates shell code that examines process table at execution time

  cat <<EOF
ps_output=\$(ps auxww 2>>"$LOG_FILE" | grep '[w]g-quick' || true)

if [ -z "\$ps_output" ]; then
  echo "# No wg-quick processes found"
  exit 0
fi

echo "\$ps_output" | while IFS= read -r line; do
  pid=\$(echo "\$line" | awk '{print \$2}')
  cmd=\$(echo "\$line" | awk '{for(i=11;i<=NF;i++) printf \$i " "; print ""}')
  config=\$(echo "\$cmd" | sed -n 's/.*wg-quick[[:space:]]*up[[:space:]]*\([^[:space:]]*\).*/\1/p')

  if echo "\$config" | grep -q "^$VPN_SWITCH_BASE/.session/"; then
    session_id=\$(echo "\$config" | sed "s|^$VPN_SWITCH_BASE/.session/\([^/]*\)/.*|\1|")
    interface=\$(basename "\$config" .conf 2>>"$LOG_FILE" || echo 'unknown')
    echo "#"
    echo "# ✓ wg-quick (PID \$pid) [managed by this instance]"
    echo "#   Config: \$config"
    echo "#   Session: \$session_id"
    echo "#   Interface: \$interface"
  elif echo "\$config" | grep -q '/.session/'; then
    other_base=\$(echo "\$config" | sed 's|\(.*\)/.session/.*|\1|')
    interface=\$(basename "\$config" .conf 2>>"$LOG_FILE" || echo 'unknown')
    echo "#"
    echo "# ⚠ wg-quick (PID \$pid) [different vpn-switch instance]"
    echo "#   Config: \$config"
    echo "#   Instance: \$other_base"
    echo "#   Interface: \$interface"
  else
    interface=\$(basename "\$config" .conf 2>>"$LOG_FILE" || echo 'unknown')
    echo "#"
    echo "# ⚠ wg-quick (PID \$pid) [NOT managed by vpn-switch]"
    echo "#   Config: \$config"
    echo "#   Interface: \$interface"
    for session_dir in "$VPN_SWITCH_BASE/.session"/*; do
      [ -d "\$session_dir" ] || continue
      our_interface=\$(cat "\$session_dir/interface" 2>>"$LOG_FILE" || true)
      if [ "\$our_interface" = "\$interface" ]; then
        our_session=\$(basename "\$session_dir")
        echo "#   ⚠ WARNING: Interface conflict with our session \$our_session!"
      fi
    done
  fi
done
EOF
}

#@help ___wireguard_stop0
# @internal batch sibling of 'wireguard stop' (stops all WireGuard sessions)
#@end
___wireguard_stop0() {
  local session_base="$VPN_SWITCH_BASE/.session"

  if [ ! -d "$session_base" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" log \"No WireGuard sessions to stop\""
    return 0
  fi

  # Find all wireguard sessions
  local found_session=0
  for session_dir in "$session_base"/*/; do
    [ ! -d "$session_dir" ] && continue

    local session_protocol=$(cat "$session_dir/protocol" 2>>"$LOG_FILE")

    # Skip non-wireguard sessions
    [ "$session_protocol" != "wireguard" ] && continue

    # Skip inactive sessions (not running)
    is_session_alive "$session_dir" || continue

    local session_interface=$(cat "$session_dir/interface" 2>>"$LOG_FILE")

    # Legacy: infer interface if missing
    if [ -z "$session_interface" ]; then
      session_interface="$VPN_SWITCH_INTERFACE_wireguard"
    fi

    # Script path uses literal variable reference for portability
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" wireguard disconnect $session_interface"
    found_session=1
  done

  # If no WireGuard sessions were found, output log message
  if [ "$found_session" -eq 0 ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" log \"No WireGuard sessions to stop\""
  fi
}

#@help __wireguard_stop1
# @command wireguard stop [<interface>]
# @summary Stop WireGuard sessions, or one specific interface
# @group   wireguard
# @param   interface  interface to stop (default: all WireGuard sessions)
# @returns disconnect commands
# @example vpn-switch wireguard stop
# @see     wireguard start
#@end
__wireguard_stop1() {
  local interface="$1"

  # Validate session exists
  local session_pid=$(find_session_by_interface "$interface")

  if [ -z "$session_pid" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"No wireguard session found for interface: $interface\""
    return
  fi

  # Output disconnect command
  # Script path uses literal variable reference for portability
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" wireguard disconnect $interface"
}

#@help _wireguard_import1
# @command wireguard import <file>
# @summary Import a WireGuard .conf file into the database
# @group   wireguard
# @param   file  path to a .conf file to import
# @returns shell commands (copy config into the database)
# @example vpn-switch wireguard import ~/Downloads/wg-CH-201.conf
# @see     wireguard list
#@end
_wireguard_import1() {
  local source_path="$1"

  # Validate file exists
  if [ ! -f "$source_path" ]; then
    generate_error "Config file not found: $source_path"
    return 0
  fi

  # Extract filename
  local filename=$(basename -- "$source_path")

  # Validate extension
  case "$filename" in
    *.conf) ;;
    *)
      generate_error "Invalid config file extension - expected .conf: $filename"
      return 0
      ;;
  esac

  # Check if config already exists in protocol directory
  local dest_path="$VPN_SWITCH_BASE/wireguard/$filename"
  if [ -f "$dest_path" ]; then
    generate_error "Config already exists: wireguard/$filename"
    return 0
  fi

  # Output import commands
  cat <<EOF
# Import WireGuard config: $filename
$MODIFY_FILE_COPY "$source_path" "$dest_path"
$MODIFY_FILE_PERMS 0400 "$dest_path"
echo "# Imported: wireguard/$filename" >&2
EOF
}

