_wireguard_list1() {
  local category="$1"
  local category_dir="$VPN_SWITCH_BASE/wireguard/$category"

  # Check if category exists
  if [ ! -d "$category_dir" ]; then
    generate_error "Category not found: $category"
    return 0
  fi

  # Output listing with hierarchy prefixes and comment headers
  echo "# === Links in wireguard/$category ==="
  echo "#"

  # List all items in category with targets (inline to show arrows)
  # Note: Categories typically contain symlinks, show their targets
  for item in "$category_dir"/*; do
    # Skip if no items found (glob didn't match)
    [ ! -e "$item" ] && [ ! -L "$item" ] && continue

    # Skip items with newlines (cannot output safely)
    has_newline_in_path "$item" && continue

    local item_name=$(basename -- "$item")

    # Show symlink target if it's a link
    if [ -L "$item" ]; then
      local target=$(readlink "$item")
      echo "wireguard/$category/$item_name -> $target"
    else
      # Regular file/directory (shouldn't happen in categories, but be safe)
      echo "wireguard/$category/$item_name"
    fi
  done | sort
}

#@help _wireguard_add1
# @command wireguard add <category> [<config> [<alias>]]
# @summary Create a category, or link a config into one
# @group   wireguard
# @param   category  category to create or add to
# @param   config    config to link into the category
# @param   alias     custom link name (default: derived)
# @returns shell commands (create category / create symlink)
# @example vpn-switch wireguard add privacy wg-CH-201.conf switzerland
# @see     wireguard link
#@end
_wireguard_add1() {
  local category="$1"
  local wg_dir="$VPN_SWITCH_BASE/wireguard"
  local category_path="$wg_dir/$category"

  # Check if category already exists (file, link, or directory)
  if [ -e "$category_path" ] || [ -L "$category_path" ]; then
    generate_error "Category already exists: $category"
    return 0
  fi

  # Output commands to create category
  cat <<EOF
# Create WireGuard category: $category
$MODIFY_DIR_CREATE "$category_path"
$MODIFY_FILE_PERMS 0755 "$category_path"
echo "# Created category: wireguard/$category" >&2
EOF
}

#@help __wireguard_add2
# @internal arity-2 sibling of 'wireguard add' (config into category)
#@end
__wireguard_add2() {
  local category="$1"
  local target="$2"
  local wg_dir="$VPN_SWITCH_BASE/wireguard"
  local category_dir="$wg_dir/$category"

  # Validate category exists and is a directory
  if [ ! -d "$category_dir" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"Category not found: $category\""
    return
  fi

  # Validate target exists in protocol directory
  # Note: Target could be a .conf file or a symlink
  local target_path="$wg_dir/$target"
  if [ ! -e "$target_path" ] && [ ! -L "$target_path" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"Target not found in wireguard directory: $target\""
    return
  fi

  # Check if link already exists in category
  local link_path="$category_dir/$target"
  if [ -e "$link_path" ] || [ -L "$link_path" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"Link already exists in category $category: $target\""
    return
  fi

  # Delegate to add3 with target as both target and alias
  # Script path included in output (expands inside run_env)
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" wireguard add \"$category\" \"$target\" \"$target\""
}

