#@help _wireguard_remove1
# @command wireguard remove <name>
# @summary Remove a config, link or category (with safety checks)
# @group   wireguard
# @param   name  config, link or category to remove
# @returns shell commands (remove the target)
# @example vpn-switch wireguard remove old-server
#@end
_wireguard_remove1() {
  local name="$1"
  local wg_dir="$VPN_SWITCH_BASE/wireguard"
  local target_path="$wg_dir/$name"

  # Validate target exists
  if [ ! -e "$target_path" ] && [ ! -L "$target_path" ]; then
    generate_error "Target not found in wireguard directory: $name"
    return 0
  fi

  # If it's a symlink, remove without checks
  if [ -L "$target_path" ]; then
    cat <<EOF
# Remove symlink from wireguard/: $name
$MODIFY_LINK_REMOVE "$target_path"
echo "Removed link: wireguard/$name"
EOF
    return 0
  fi

  # If it's a directory (category), check if empty
  if [ -d "$target_path" ]; then
    # Check if directory is empty
    if [ -n "$(ls -A "$target_path" 2>>"$LOG_FILE")" ]; then
      generate_error "Category not empty: $name"
      display plain "Remove all links from category first, then retry"
      return 0
    fi

    # Directory is empty, safe to remove
    cat <<EOF
# Remove empty category: $name
rmdir "$target_path"
echo "Removed category: wireguard/$name"
EOF
    return 0
  fi

  # It's a file - check if it's a config
  case "$name" in
    *.conf)
      # Check for active sessions using this config
      local session_dir="$VPN_SWITCH_BASE/.session"
      if [ -d "$session_dir" ]; then
        for session in "$session_dir"/*; do
          if [ -d "$session" ] && [ -f "$session/original" ]; then
            local original=$(cat "$session/original")
            if [ "$original" = "$target_path" ]; then
              local pid=$(basename -- "$session")
              generate_error "Config in use by active session - PID $pid: $name"
              display plain "Remove the session first with: vpn-switch session remove $pid"
              return 0
            fi
          fi
        done
      fi

      # Check for symlinks referencing this config
      local refs=""
      local ref_count=0

      # Canonicalize target path for comparison
      local canonical_target=$(readlink -f "$target_path")

      # Check protocol directory for symlinks
      for item in "$wg_dir"/*; do
        if [ -L "$item" ] && [ "$(readlink -f "$item")" = "$canonical_target" ]; then
          refs="$refs
  - wireguard/$(basename -- "$item")"
          ref_count=$((ref_count + 1))
        fi
      done

      # Check categories for symlinks
      for category in "$wg_dir"/*; do
        if [ -d "$category" ]; then
          for item in "$category"/*; do
            if [ -L "$item" ] && [ "$(readlink -f "$item")" = "$canonical_target" ]; then
              refs="$refs
  - wireguard/$(basename -- "$category")/$(basename -- "$item")"
              ref_count=$((ref_count + 1))
            fi
          done
        fi
      done

      # If references found, refuse with error
      if [ $ref_count -gt 0 ]; then
        generate_error "Config has $ref_count symlink reference(s): $name"
        display plain "$refs"
        display plain "Remove symlinks first, or use: vpn-switch wireguard clean | sh"
        return 0
      fi

      # No references, safe to remove
      cat <<EOF
# Remove config from wireguard/: $name
$MODIFY_FILE_REMOVE "$target_path"
echo "Removed config: wireguard/$name"
EOF
      ;;
    *)
      # Not a .conf file and not a symlink - refuse
      generate_error "Cannot remove: $name - not a config file or symlink"
      return 0
      ;;
  esac
}

#@help _wireguard_remove2
# @internal arity-2 variant of 'wireguard remove' (remove link from a category)
#@end
_wireguard_remove2() {
  local category="$1"
  local name="$2"
  local wg_dir="$VPN_SWITCH_BASE/wireguard"
  local category_path="$wg_dir/$category"
  local target_path="$category_path/$name"

  # Validate category exists
  if [ ! -d "$category_path" ]; then
    generate_error "Category not found: $category"
    return 0
  fi

  # Validate target exists in category
  if [ ! -e "$target_path" ] && [ ! -L "$target_path" ]; then
    generate_error "Link not found in category $category: $name"
    return 0
  fi

  # Output commands to remove
  cat <<EOF
# Remove from category $category: $name
$MODIFY_LINK_REMOVE "$target_path"
echo "Removed from $category: $name"
EOF
}

#@help _wireguard_validate0
# @command wireguard validate
# @summary Check WireGuard symlink integrity in the database
# @group   wireguard
# @returns validation report
# @example vpn-switch wireguard validate
# @see     wireguard clean
#@end
_wireguard_validate0() {
  local wg_dir="$VPN_SWITCH_BASE/wireguard"
  local has_errors=0
  local has_warnings=0

  # Check if wireguard directory exists
  if [ ! -d "$wg_dir" ]; then
    echo "# [ERROR] WireGuard directory not found: $wg_dir"
    return 1
  fi

  echo "# === WireGuard Configuration Validation ==="
  echo "#"

  # Check for files with newlines in name (cannot be safely handled)
  echo "# Checking for files with newlines in name..."
  for item in "$wg_dir"/*; do
    # Skip if no items
    [ ! -e "$item" ] && [ ! -L "$item" ] && continue

    # Check for newlines in path
    if has_newline_in_path "$item"; then
      echo "# [ERROR] File has newline in name (cannot be safely handled)"
      has_errors=1
    fi
  done

  # Check for broken symlinks in protocol directory
  echo "#"
  echo "# Checking protocol directory for broken symlinks..."
  for item in "$wg_dir"/*; do
    # Skip if no items
    [ ! -e "$item" ] && [ ! -L "$item" ] && continue

    # Skip files with newlines (already reported above)
    has_newline_in_path "$item" && continue

    # Check if symlink and broken
    if [ -L "$item" ] && [ ! -e "$item" ]; then
      echo "# [ERROR] Broken symlink: wireguard/$(basename -- "$item")"
      has_errors=1
    fi
  done

  # Check for broken symlinks in categories
  echo "#"
  echo "# Checking categories for broken symlinks..."
  for category in "$wg_dir"/*; do
    [ ! -d "$category" ] && continue

    # Skip categories with newlines (already reported above)
    has_newline_in_path "$category" && continue

    local category_name=$(basename -- "$category")

    for item in "$category"/*; do
      # Skip if no items
      [ ! -e "$item" ] && [ ! -L "$item" ] && continue

      # Skip items with newlines
      if has_newline_in_path "$item"; then
        echo "# [ERROR] File has newline in name (in category $category_name)"
        has_errors=1
        continue
      fi

      # Check if symlink and broken
      if [ -L "$item" ] && [ ! -e "$item" ]; then
        echo "# [ERROR] Broken symlink: wireguard/$category_name/$(basename -- "$item")"
        has_errors=1
      fi
    done
  done

  # Check for naming conflicts (file and directory with same name)
  echo "#"
  echo "# Checking for naming conflicts..."
  for item in "$wg_dir"/*; do
    [ ! -e "$item" ] && [ ! -L "$item" ] && continue

    # Skip items with newlines (already reported above)
    has_newline_in_path "$item" && continue

    local base_name=$(basename -- "$item")

    # Skip directories and non-conf files for this check
    [ -d "$item" ] && continue
    [ ! -f "$item" ] && [ ! -L "$item" ] && continue

    # Check if there's also a directory with the same name (without .conf)
    local name_without_ext="${base_name%.conf}"
    if [ -d "$wg_dir/$name_without_ext" ]; then
      echo "# [WARNING] Naming conflict: wireguard/$base_name (file) and wireguard/$name_without_ext/ (directory)"
      has_warnings=1
    fi
  done

  # Check for basic config file validity (just check if readable and non-empty)
  echo "#"
  echo "# Checking config file validity..."
  for item in "$wg_dir"/*.conf; do
    # Skip if glob didn't match any files
    [ ! -e "$item" ] && continue

    # Skip items with newlines (already reported above)
    has_newline_in_path "$item" && continue

    local config_name=$(basename -- "$item")

    # Check if readable
    if [ ! -r "$item" ]; then
      echo "# [ERROR] Config not readable: wireguard/$config_name"
      has_errors=1
      continue
    fi

    # Check if non-empty
    if [ ! -s "$item" ]; then
      echo "# [WARNING] Config file is empty: wireguard/$config_name"
      has_warnings=1
      continue
    fi

    # Check for basic WireGuard sections
    if ! grep -q "^\[Interface\]" "$item" 2>>"$LOG_FILE"; then
      echo "# [WARNING] Config missing [Interface] section: wireguard/$config_name"
      has_warnings=1
    fi
  done

  # Summary
  echo "#"
  if [ $has_errors -eq 0 ] && [ $has_warnings -eq 0 ]; then
    echo "# Validation complete: No issues found"
    return 0
  elif [ $has_errors -eq 0 ]; then
    echo "# Validation complete: Warnings found (no errors)"
    return 0
  else
    echo "# Validation complete: Errors found"
    return 1
  fi
}

#@help ___wireguard_clean0
# @command wireguard clean [<category>]
# @summary Generate cleanup commands for broken links
# @group   wireguard
# @param   category  restrict cleanup to one category
# @returns shell commands (review, then pipe to sh)
# @example vpn-switch wireguard clean | sh
# @see     wireguard validate
#@end
___wireguard_clean0() {
  local wg_dir="$VPN_SWITCH_BASE/wireguard"

  # Check if wireguard directory exists
  if [ ! -d "$wg_dir" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"WireGuard directory not found: $wg_dir\""
    return 0
  fi

  echo "# Clean up broken symlinks in wireguard/"
  echo "#"
  echo "# This script will remove broken symlinks."
  echo "# Review the commands below, then run: vpn-switch wireguard clean | sh"
  echo "#"
  safety_first_message
  echo "#"

  local found_broken=0

  # Check protocol directory for broken symlinks
  for item in "$wg_dir"/*; do
    # Skip if no items
    [ ! -e "$item" ] && [ ! -L "$item" ] && continue

    # Skip items with newlines (cannot generate valid commands)
    if has_newline_in_path "$item"; then
      echo "# WARNING: Skipping file with newline in name (cannot be safely handled)"
      continue
    fi

    # Check if symlink and broken
    if [ -L "$item" ] && [ ! -e "$item" ]; then
      local item_name=$(basename -- "$item")
      echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" wireguard remove \"$item_name\""
      found_broken=1
    fi
  done

  # Check categories for broken symlinks
  for category in "$wg_dir"/*; do
    [ ! -d "$category" ] && continue

    # Skip categories with newlines
    has_newline_in_path "$category" && continue

    local category_name=$(basename -- "$category")

    for item in "$category"/*; do
      # Skip if no items
      [ ! -e "$item" ] && [ ! -L "$item" ] && continue

      # Skip items with newlines (cannot generate valid commands)
      if has_newline_in_path "$item"; then
        echo "# WARNING: Skipping file with newline in name (cannot be safely handled)"
        continue
      fi

      # Check if symlink and broken
      if [ -L "$item" ] && [ ! -e "$item" ]; then
        local item_name=$(basename -- "$item")
        echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" wireguard remove \"$category_name\" \"$item_name\""
        found_broken=1
      fi
    done
  done

  if [ $found_broken -eq 0 ]; then
    echo "# No broken symlinks found"
  fi
}

