#@help _wireguard_patch1
# @command wireguard patch <config>
# @summary Preview the patched config that would be used to connect
# @group   wireguard
# @param   config  config to preview
# @returns the patched configuration
# @example vpn-switch wireguard patch wg-CH-201.conf
#@end
_wireguard_patch1() {
  local config_name="$1"
  local wg_dir="$VPN_SWITCH_BASE/wireguard"

  # Resolve config path (handle both relative and absolute paths)
  local config_path=""
  case "$config_name" in
    /*)
      # Absolute path - use as-is
      config_path="$config_name"
      ;;
    *)
      # Relative path - resolve from wireguard directory
      config_path="$wg_dir/$config_name"
      ;;
  esac

  # Validate config exists
  if [ ! -f "$config_path" ]; then
    generate_error "Config file not found: $config_path"
    return 0
  fi

  # Validate it's readable
  if [ ! -r "$config_path" ]; then
    generate_error "Config file not readable: $config_path"
    return 0
  fi

  # Output patched config to stdout using patch_wireguard_config helper
  # Note: /dev/stdout is POSIX-compliant for output redirection
  patch_wireguard_config "$config_path" /dev/stdout
}

#@help _wireguard_info1
# @command wireguard info <category>
# @summary Show category details, including config expiry dates
# @group   wireguard
# @param   category  category to inspect
# @returns category report
# @example vpn-switch wireguard info privacy
#@end
_wireguard_info1() {
  local category="$1"
  local wg_dir="$VPN_SWITCH_BASE/wireguard"
  local category_path="$wg_dir/$category"

  # Validate category exists and is a directory
  if [ ! -d "$category_path" ]; then
    generate_error "Category does not exist: $category"
    return 0
  fi

  # Count configs and links
  local config_count=0
  local link_count=0

  for entry in "$category_path"/*; do
    [ -e "$entry" ] || continue
    if [ -L "$entry" ]; then
      link_count=$((link_count + 1))
    elif [ -f "$entry" ] && [ "${entry%.conf}" != "$entry" ]; then
      config_count=$((config_count + 1))
    fi
  done

  # Display formatted output
  cat <<EOF
# Category: $category
#
# Configs: $config_count
# Links:   $link_count
# Path:    $category_path
#
# Contents:
EOF

  # List all entries with expiry information
  for entry in "$category_path"/*; do
    [ -e "$entry" ] || continue
    local basename_entry=$(basename -- "$entry")

    if [ -L "$entry" ]; then
      # Follow symlink to get actual config file
      local target=$(readlink "$entry")
      local target_path="$category_path/$target"

      # Resolve relative symlinks
      if [ "${target#/}" = "$target" ]; then
        # Relative path - resolve it
        target_path=$(cd "$(dirname "$entry")" && cd "$(dirname "$target")" && pwd)/$(basename "$target")
      fi

      # Get expiry for the target
      local expiry_info=""
      if [ -f "$target_path" ]; then
        expiry_info=$(get_wireguard_expiry_status "$target_path")
      fi

      if [ -n "$expiry_info" ]; then
        echo "#   $basename_entry -> $target  $expiry_info"
      else
        echo "#   $basename_entry -> $target"
      fi
    elif [ -f "$entry" ]; then
      # Regular file - get expiry
      local expiry_info=$(get_wireguard_expiry_status "$entry")
      if [ -n "$expiry_info" ]; then
        echo "#   $basename_entry  $expiry_info"
      else
        echo "#   $basename_entry"
      fi
    else
      echo "#   $basename_entry"
    fi
  done
}

#@help ___wireguard_dump0
# @command wireguard dump
# @summary Generate restorable shell commands for all WireGuard configs
# @group   wireguard
# @returns shell commands (restorable database dump)
# @example vpn-switch wireguard dump
# @see     dump
#@end
___wireguard_dump0() {
  local wg_dir="$VPN_SWITCH_BASE/wireguard"
  local session_pseudo="$VPN_SWITCH_BASE/session"

  # Validate wireguard directory exists
  if [ ! -d "$wg_dir" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error \"WireGuard directory not found: $wg_dir\""
    return 0
  fi

  # Phase 1: Import all configs (absolute paths from SOURCE database)
  echo "# Import wireguard configurations"
  for config_file in "$wg_dir"/*.conf; do
    [ ! -f "$config_file" ] && continue

    # Skip files with newlines in name (cannot be safely represented in line-based dump)
    if has_newline_in_path "$config_file"; then
      echo "# WARNING: Skipping file with newline in name (cannot be safely dumped)"
      continue
    fi

    # Use absolute path for imports with proper quoting
    # Output literal \$VPN_SWITCH_CONTEXT_SCRIPT so it expands during restore
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" wireguard import \"$config_file\""
  done

  # Output separator
  echo ""

  # Phase 2: Create categories
  echo "# Create categories"
  scan_wireguard_categories | while IFS= read -r category_path; do
    # Extract category name (remove wireguard/ prefix and / suffix)
    local category=$(echo "$category_path" | sed 's|^wireguard/||' | sed 's|/$||')
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" wireguard add $category"
  done

  # Output separator
  echo ""

  # Phase 3: Create protocol-level links (aliases in wireguard/ directory)
  echo "# Create protocol-level links"
  scan_wireguard_links | while IFS= read -r link_info; do
    # Parse "wireguard/alias -> target" format
    local alias=$(echo "$link_info" | sed 's|^wireguard/||' | sed 's| ->.*||')
    local target=$(echo "$link_info" | sed 's|.* -> ||')
    # Normalize target: strip ./ prefix (wireguard link will add it back)
    target=$(echo "$target" | sed 's|^\./||')
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" wireguard link $alias $target"
  done

  # Output separator
  echo ""

  # Phase 4: Create category links
  echo "# Create category links"
  scan_wireguard_categories | while IFS= read -r category_path; do
    # Extract category name
    local category=$(echo "$category_path" | sed 's|^wireguard/||' | sed 's|/$||')
    local category_dir="$wg_dir/$category"

    # Scan for links in this category
    for link_file in "$category_dir"/*; do
      [ ! -L "$link_file" ] && continue
      local link_name=$(basename "$link_file")
      local target=$(readlink "$link_file")
      local target_basename=$(basename "$target")

      # Determine if this is arity-2 (link and target have same name) or arity-3 (different)
      local target_base=$(basename "$target" .conf)
      if [ "$link_name" = "$target_base" ] || [ "$link_name" = "$target_basename" ]; then
        # Arity-2: same name
        echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" wireguard add $category $target_basename"
      else
        # Arity-3: custom name
        echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" wireguard add $category $target_basename $link_name"
      fi
    done
  done

  # Output separator
  echo ""

  # Note: Phase 5 (session dumping) removed - now handled by ___session_dump0()
  # This ensures multi-protocol sessions are dumped correctly (not just WireGuard)
}

#@help __wireguard_help0
# @command wireguard help
# @summary Show WireGuard command help
# @group   wireguard
# @returns help text
# @example vpn-switch wireguard help
#@end
__wireguard_help0() {
  # Backward compatibility: delegate to new pattern "help wireguard"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" help wireguard"
}

patch_wireguard_config() {
  local source_config="$1"
  local dest_config="$2"

  # Phase-based approach: Strip existing DNS hooks (DNS handled by DNS phase)
  # Simply remove PostUp/PostDown lines that contain resolvconf
  awk '
    # Skip PostUp/PostDown lines that contain resolvconf (DNS hooks)
    /^PostUp.*resolvconf/ { next }
    /^PostDown.*resolvconf/ { next }

    # Print all other lines
    { print }
  ' "$source_config" > "$dest_config"

  $MODIFY_FILE_PERMS 0640 "$dest_config"
}

get_wireguard_remotes() {
  local config_file="$1"

  awk '/^\[Peer\]/,/^$/ {
    if ($1 == "Endpoint") {
      # Extract IP from "IP:port"
      split($3, parts, ":")
      print parts[1]
    }
  }' "$config_file"
}

scan_wireguard_links() {
  local wg_dir="$VPN_SWITCH_BASE/wireguard"

  # Find all symlinks that are NOT config files (i.e., protocol-level aliases)
  for item in "$wg_dir"/*; do
    # Skip if no items found
    [ ! -e "$item" ] && [ ! -L "$item" ] && continue

    # Skip directories (categories)
    [ -d "$item" ] && continue

    # Skip if not a symlink
    [ ! -L "$item" ] && continue

    # Skip items with newlines (cannot output safely)
    has_newline_in_path "$item" && continue

    local item_name=$(basename -- "$item")

    # Skip .conf files (those are listed in configs section)
    case "$item_name" in
      *.conf) continue ;;
    esac

    # Show symlink with target
    local target=$(readlink "$item")
    echo "wireguard/$item_name -> $target"
  done | sort
}

scan_wireguard_categories() {
  local wg_dir="$VPN_SWITCH_BASE/wireguard"

  # Find all subdirectories, add hierarchy prefix and "/" suffix
  for item in "$wg_dir"/*; do
    # Skip if not a directory
    [ ! -d "$item" ] && continue

    # Skip items with newlines (cannot output safely)
    has_newline_in_path "$item" && continue

    local item_name=$(basename -- "$item")
    echo "wireguard/$item_name/"
  done | sort
}

get_wireguard_expiry_status() {
  local config_file="$1"

  if [ ! -f "$config_file" ]; then
    echo ""
    return
  fi

  # VPN provider WireGuard configs expire 1 year after creation
  # Use file birth time (creation time) as baseline
  local file_ctime
  local estimated_expiry
  local current_time
  local days_left

  # Get file creation time (birth time)
  file_ctime=$($CMD_STAT_CTIME "$config_file" 2>>"$LOG_FILE" || echo "0")

  if [ "$file_ctime" = "0" ] || [ "$file_ctime" = "-" ]; then
    # Birth time not available, fall back to modification time
    file_ctime=$($CMD_STAT_MTIME "$config_file" 2>>"$LOG_FILE" || echo "0")
  fi

  if [ "$file_ctime" = "0" ]; then
    echo "[? unknown]"
    return
  fi

  # Add 1 year (365 days * 24 hours * 3600 seconds) to file creation time
  estimated_expiry=$((file_ctime + 31536000))
  current_time=$(date +%s)

  # Calculate days difference
  days_left=$(( (estimated_expiry - current_time) / 86400 ))

  # Format output with status indicators
  if [ "$days_left" -lt 0 ]; then
    # Expired
    echo "[✗ expired: ${days_left#-}d ago]"
  elif [ "$days_left" -le 30 ]; then
    # Expiring soon (within 30 days)
    echo "[⚠ expiring: ${days_left}d]"
  else
    # Valid (more than 30 days)
    echo "[✓ valid: ${days_left}d]"
  fi
}

scan_wireguard_configs() {
  local wg_dir="$VPN_SWITCH_BASE/wireguard"

  # Find all .conf files (both regular files and symlinks ending in .conf)
  for item in "$wg_dir"/*.conf; do
    # Skip if glob didn't match
    [ ! -e "$item" ] && [ ! -L "$item" ] && continue

    # Skip items with newlines (cannot output safely)
    has_newline_in_path "$item" && continue

    local item_name=$(basename -- "$item")
    echo "wireguard/$item_name"
  done | sort
}

scan_category_links() {
  local category="$1"
  local category_dir="$VPN_SWITCH_BASE/wireguard/$category"

  # Find all items in category, add hierarchy prefix
  # Note: Categories contain symlinks, not actual files
  for item in "$category_dir"/*; do
    # Skip if glob didn't match or not a symlink
    [ ! -L "$item" ] && continue

    # Skip items with newlines (cannot output safely)
    has_newline_in_path "$item" && continue

    local item_name=$(basename -- "$item")
    echo "wireguard/$category/$item_name"
  done | sort
}

